import React, { useContext, useEffect, useState } from 'react';

import Header from '@components/Header';
import LoginHero from '@components/LoginHero';
import PlanSelectionHero from '@components/HeroBanner_planSelection';
import Loading from '@components/ui/Loading';

import { UserContext } from '@providers/User';
// import SubscriptionStatusCard from '@components/userControlPanel/UserForm/AdminMenu/SubscriptionStatusCard';

// import * as styles from './planExpiryGateway.module.css';

/** Displays login form if user isn't logged in
 * Displays plan selection dialog if user has no active plan or plan has expired
 * Note that, it does not display the header in case user has an active plan since it is left to the app components rendered as children to implement it.
 * Imported in page layout
 */
export default function PlanExpiryGateway({ children }) {
	const [isLoadingDone, setIsLoadingDone] = useState(false);
	const { id, exp, isPlanActive, checkIfPlanActive } = useContext(UserContext);
	// const [isPlanActive, setIsPlanActive] = useState(async () => {
	// 	if (!checkIfPlanActive || typeof checkIfPlanActive !== 'function') return false;
	// 	return await checkIfPlanActive();
	// }); // useState(false);

	useEffect(() => {
		// console.log('usrPlanExpiry:', exp);
		// console.log('isPlanActive:', isPlanActive);
		if (!checkIfPlanActive || typeof checkIfPlanActive !== 'function') return;
		(async () => {
			// const isActive = await checkIfPlanActive();
			await checkIfPlanActive();
			// console.log('isActive', isActive);
			// setIsPlanActive(isActive);
		})();
	}, [exp, isPlanActive]);

	useEffect(() => {
		//in order to prevent flickering when 'id' or 'isPlanActive' is being read from the context
		//since the inital state of 'id' is 'null' and 'isPlanActive' is 'false' and then when the actual value comes in (it causes a flickering effect)
		//this flickering effect may only be visible in dev mode but need to check
		setTimeout(() => {
			setIsLoadingDone(true);
		}, 100);
	}, []);
	// return <div className={styles.paidAreaContentC}>{isPlanActive ? children : <SubscriptionStatusCard />}</div>;
	if (!isLoadingDone) return <Loading coverFullPage={true} />;
	// return isPlanActive ? children : <PlanSelectionHero />;

	return (
		<>
			{!isPlanActive && <Header />}
			{id ? ( //if logged-in isPlanActive ? ( children //show if user is logged-in and has an active plan ) : (
				isPlanActive ? (
					children
				) : (
					<PlanSelectionHero />
				)
			) : (
				<LoginHero />
			)}
		</>
	);
}
